checker_dsl:
EXISTS (`BinaryExpr outer`, `BinaryExpr inner`) {
  AND {
    (`inner is a direct child operand of outer`),
    NOT {
      EXISTS (`BinaryExpr parent`, `BinaryExpr idxChild`) {
        AND {
          (`inner is the idxChild-th child of parent`),
          OR {
            AND {
              OR {
                (`inner is an AddExpr`),
                (`inner is a MulExpr`),
                (`inner is a BitwiseExpr`),
                (`inner is a LogicalExpr`)
              },
              (`parent has the same operator kind as inner`)
            },
            AND {
              (`inner is an EqualityTest`),
              (`parent is an EqualityTest`)
            },
            AND {
              (`inner is a MulExpr`),
              (`parent is a DivExpr`),
              (`idxChild = 0`)
            },
            AND {
              (`inner is a DivExpr`),
              (`parent is a RemExpr`),
              (`idxChild = 0`)
            },
            AND {
              (`inner is an AddExpr`),
              (`parent is a SubExpr`),
              (`idxChild = 0`)
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`BinaryExpr parent`) {
        AND {
          (`inner is a direct child operand of parent`),
          OR {
            AND {
              (`parent is a RelationExpr`),
              OR {
                (`inner is an ArithmeticExpr`),
                (`inner is a ShiftExpr`)
              }
            },
            AND {
              (`parent is a LogicalExpr`),
              (`inner is a RelationExpr`)
            }
          }
        }
      }
    },
    NOT { AND { (`inner is parenthesized`) } },
    EXISTS (`BinaryExpr wsinnerElem`) {
      AND {
        (`wsinnerElem = operatorWS(inner)`),
        (`wsinnerElem % 2 = 0`)
      }
    },
    EXISTS (`BinaryExpr wsouterElem`) {
      AND {
        (`wsouterElem = operatorWS(outer)`),
        (`wsouterElem % 2 = 0`)
      }
    },
    (`wsinnerElem > wsouterElem`)
  }
}
